import React, { useState, useMemo } from "react";
import { Card, Typography, Row, Col, Space, Breadcrumb, theme, DatePicker, Select, Button } from "antd";
import { ReconciliationOutlined, HomeOutlined, FilterOutlined, DownloadOutlined } from "@ant-design/icons";
import EChart from "@/framework/components/Chart/EChart";
import { useI18n } from "@/framework/i18n/hooks";
import { mockStorages } from "../../dashboard/data/mockData";
import { faker } from "@faker-js/faker";

const { Title } = Typography;

export default function StatDayPage() {
  const { t } = useI18n(["storageLocker", "common"]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const option = useMemo(() => {
    const days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
    const targets = selectedIds.length > 0 
      ? mockStorages.filter(s => selectedIds.includes(s.id))
      : mockStorages.slice(0, 3);

    return {
      tooltip: { trigger: "axis", axisPointer: { type: "shadow" } },
      legend: { show: targets.length > 1, top: 0, left: "center", orient: "horizontal" },
      grid: { top: 40, left: "3%", right: "4%", bottom: "3%", containLabel: true },
      xAxis: [{ type: "category", data: days, axisTick: { alignWithLabel: true } }],
      yAxis: [{ type: "value" }],
      series: targets.map(locker => ({
        name: locker.name,
        type: "bar",
        barWidth: targets.length > 1 ? "15%" : "60%",
        data: days.map(() => faker.number.int({ min: 50, max: 300 })),
      })),
    };
  }, [selectedIds]);

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24 }}>
      <Breadcrumb
        items={[
          { title: <HomeOutlined />, href: "/" },
          { title: t("storageLocker:navigation.statistics") },
          { title: t("storageLocker:navigation.statDay") },
        ]}
      />

      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[16, 16]} align="middle">
          <Col md={8} lg={6}>
            <Title level={4} style={{ margin: 0 }}>
              <ReconciliationOutlined style={{ marginRight: 8, color: "#13c2c2" }} />
              {t("storageLocker:navigation.statDay")}
            </Title>
          </Col>
          <Col flex="auto">
            <Row gutter={16} justify="end">
              <Col span={10}>
                <Select 
                  mode="multiple"
                  placeholder={t("storageLocker:dashboard.selectPlaceholder")}
                  style={{ width: "100%" }}
                  maxTagCount="responsive"
                  value={selectedIds}
                  onChange={setSelectedIds}
                  options={mockStorages.map(s => ({ label: s.name, value: s.id }))}
                  allowClear
                />
              </Col>
              <Col>
                <Space>
                  <DatePicker.MonthPicker placeholder={t("storageLocker:statistics.common.selectMonth")} />
                  <Button type="primary" icon={<FilterOutlined />}>{t("common:search")}</Button>
                  <Button icon={<DownloadOutlined />}>{t("common:exportXlsx")}</Button>
                </Space>
              </Col>
            </Row>
          </Col>
        </Row>
      </Card>

      <Card title={t("storageLocker:statistics.day.distribution")} bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <EChart option={option} style={{ height: 400 }} />
      </Card>
    </div>
  );
}
